int ASN1C_MatchingCondItem_Choice::DecodeFrom (OSRTMessageBufferIF& msgBuf, OSBOOL free)
{
   int stat = setMsgBuf (msgBuf, TRUE);
   if (stat != 0) return (stat);

   asn1Init_MatchingCondItem_Choice (&msgData, free, getCtxtPtr());
   msgData.setContext (msgBuf.getContext());
   if (msgBuf.isA (OSRTMessageBufferIF::PERDecode)) {
      stat = asn1PD_MatchingCondItem_Choice (msgBuf.getCtxtPtr(), &msgData);
      ((ASN1PERDecodeBuffer&)msgBuf).byteAlign();
      return stat;
   }
   else if (msgBuf.isA (OSRTMessageBufferIF::JSONDecode)) {
      return asn1JsonDec_MatchingCondItem_Choice (msgBuf.getCtxtPtr(), &msgData);
   }
   return RTERR_NOTSUPP;
}

int asn1Init_MatchingCondItem_Choice (ASN1T_MatchingCondItem_Choice* pvalue, 
   OSBOOL free, OSCTXT *pctxt)
{
   if (0 == pvalue) return RTERR_NULLPTR;
   if (free) {
      asn1Free_MatchingCondItem_Choice (pctxt, pvalue);
   }
   else {
      pvalue->t = 0;
      OSCRTLMEMSET (&pvalue->u, 0, sizeof(pvalue->u));
   }
   return 0;
}

void asn1Free_MatchingCondItem_Choice (OSCTXT *pctxt, 
   ASN1T_MatchingCondItem_Choice* pvalue)
{
   if (0 == pvalue) return;
   switch (pvalue->t) {
      case 0: break; /* no choice; nothing to free */
      case 1:
         if (0 != pvalue->u.measLabel) {
            asn1Free_MeasurementLabel (pctxt, pvalue->u.measLabel);
            ((ASN1T_MeasurementLabel*)pvalue->u.measLabel)->~ASN1T_MeasurementLabel();
            rtxMemFreePtr (pctxt, (void*)pvalue->u.measLabel);
            pvalue->u.measLabel = 0;
         }
         break;

      case 2:
         if (0 != pvalue->u.testCondInfo) {
            asn1Free_TestCondInfo (pctxt, pvalue->u.testCondInfo);
            ((ASN1T_TestCondInfo*)pvalue->u.testCondInfo)->~ASN1T_TestCondInfo();
            rtxMemFreePtr (pctxt, (void*)pvalue->u.testCondInfo);
            pvalue->u.testCondInfo = 0;
         }
         break;

      default:
         if (0 != pvalue->u.extElem1) {
            if (!rtxCtxtTestFlag (pctxt, ASN1FASTCOPY)) {
               rtxMemFreePtr (pctxt, (void*)pvalue->u.extElem1->data);
               pvalue->u.extElem1->data = 0;
            }
            rtxMemFreePtr (pctxt, (void*)pvalue->u.extElem1);
            pvalue->u.extElem1 = 0;
         }
   }
}

void ASN1C_MatchingCondItem_Choice::MemFree ()
{
   asn1Free_MatchingCondItem_Choice (getCtxtPtr(), &msgData);
}

